/**
 * Execute a user-defined action.
 * Card templates can define userJs1 through userJs9 as functions that will be called
 * when the corresponding user action is triggered via a gesture or keyboard shortcut.
 * 
 * For example, in a card template:
 *   var userJs1 = function() { revealNextCloze(); };
 * or:
 *   var userJs1 = revealNextCloze;
 * 
 * @param {number} actionNumber - The user action number (1-9)
 */
function userAction(actionNumber) {
    var userJsName = "userJs" + actionNumber;
    try {
        var userJs = window[userJsName];
        if (typeof userJs === "function") {
            userJs();
        }
    } catch (e) {
        // Silently fail if the user action is not defined or throws an error
        console.log("Error executing " + userJsName + ": " + e);
    }
}"}

